use std::fmt::Display;

struct ReportCard<T> {
    grade: T,
    student_name: String,
    student_age: u8,
}

impl<T: Display> ReportCard<T> {
    fn print(&self) -> String {
        format!(
            "{} ({}) - achieved a grade of {}",
            &self.student_name, &self.student_age, &self.grade
        )
    }
}

fn main() {
    let report_card_numeric = ReportCard {
        grade: 3.5f32,
        student_name: "Alice".to_string(),
        student_age: 20,
    };
    assert_eq!(
        report_card_numeric.print(),
        "Alice (20) - achieved a grade of 3.5"
    );

    let report_card_letter = ReportCard {
        grade: "A+",
        student_name: "Bob".to_string(),
        student_age: 22,
    };
    assert_eq!(
        report_card_letter.print(),
        "Bob (22) - achieved a grade of A+"
